import{_ as d,o as e,c as r,ag as o}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"附录 C：名词解释","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/appendix-c.md","filePath":"chapters/appendix-c.md"}'),a={name:"chapters/appendix-c.md"};function n(h,t,c,i,s,l){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="附录-c-名词解释" tabindex="-1">附录 C：名词解释 <a class="header-anchor" href="#附录-c-名词解释" aria-label="Permalink to &quot;附录 C：名词解释&quot;">​</a></h1><p>本书涉及大量技术术语，部分来自 Claude Code 项目自身的命名约定，部分来自更广泛的技术生态。本附录按主题分类汇总了全书出现的关键术语，每条包含英文原名、中文释义和在 Claude Code 中的具体含义。</p><hr><h2 id="一、ai-与协议" tabindex="-1">一、AI 与协议 <a class="header-anchor" href="#一、ai-与协议" aria-label="Permalink to &quot;一、AI 与协议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>全称</th><th>释义</th></tr></thead><tbody><tr><td><strong>MCP</strong></td><td>Model Context Protocol</td><td>Anthropic 发布的开放协议，用于将 AI 模型与外部工具和数据源连接。Claude Code 既作为 MCP 客户端连接外部服务器，其工具系统设计也深受该协议影响。详见第 18 章。</td></tr><tr><td><strong>Prompt Cache</strong></td><td>—</td><td>Anthropic API 提供的缓存特性，允许重用已计算的 prompt 前缀。当对话历史中有大量不变内容（如系统提示词）时，缓存可以显著减少 Token 消耗和响应延迟。Claude Code 在 <code>QueryEngineConfig</code> 中通过 <code>promptCacheEnabled</code> 字段控制此特性。</td></tr><tr><td><strong>Elicitation</strong></td><td>—</td><td>MCP 协议中的一项特性，允许服务器在处理请求过程中主动向客户端（即用户）请求额外输入。这打破了传统的单向请求-响应模式，使工具交互更加灵活。</td></tr><tr><td><strong>SSE</strong></td><td>Server-Sent Events</td><td>一种基于 HTTP 的单向流式协议，服务器可以持续向客户端推送事件。在 MCP 中作为传输层选项之一，适用于需要实时流式响应但不需要双向通信的场景。</td></tr><tr><td><strong>Coordinator Mode</strong></td><td>—</td><td>Claude Code 的多 Agent 协调模式。在该模式下，一个 Coordinator Agent 负责理解用户意图并将任务拆解为子任务，分配给多个 Worker Agent 并行执行。Coordinator 负责汇总结果并呈现给用户。详见第 13 章。</td></tr><tr><td><strong>KAIROS</strong></td><td>—</td><td>Claude Code 内部的功能标识符，用于控制助手主动行为相关的能力开关。通过 Feature Gate 机制在运行时决定是否启用，属于实验性功能范畴。</td></tr><tr><td><strong>ToolSearch</strong></td><td>—</td><td>Claude Code 中的延迟工具加载机制。为减少初始 prompt 大小，系统不会在启动时将所有工具的完整 Schema 注入 prompt，而是仅提供工具名称列表，当 LLM 需要使用某个工具时再动态加载其 Schema 定义。</td></tr></tbody></table><hr><h2 id="二、开发框架与工具链" tabindex="-1">二、开发框架与工具链 <a class="header-anchor" href="#二、开发框架与工具链" aria-label="Permalink to &quot;二、开发框架与工具链&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>释义</th></tr></thead><tbody><tr><td><strong>Ink</strong></td><td>基于 React 的终端 UI 框架，允许使用 JSX 语法构建命令行界面。Claude Code 使用了一个自定义 fork 版本，对渲染性能和布局算法进行了优化。详见第 15 章。</td></tr><tr><td><strong>React Reconciler</strong></td><td>React 的核心调和算法，负责对比新旧虚拟组件树并计算最小更新。Claude Code 的 Ink 框架通过自定义 Reconciler 将 React 组件映射到终端字符输出，而非浏览器 DOM。</td></tr><tr><td><strong>Bun</strong></td><td>高性能 JavaScript 运行时和打包工具，作为 Node.js 的替代方案。Claude Code 使用 Bun 进行生产环境打包，其启动速度和打包效率相比传统工具链有显著优势。详见第 21 章。</td></tr><tr><td><strong>Zod</strong></td><td>TypeScript 优先的 Schema 验证库，用于在运行时校验数据结构。Claude Code 大量使用 Zod 定义配置文件 Schema、工具输入 Schema 和 API 响应校验，确保类型安全从编译时延伸到运行时。</td></tr><tr><td><strong>GrowthBook</strong></td><td>开源的功能开关（Feature Flag）和 A/B 实验平台。Claude Code 通过 GrowthBook 控制功能的灰度发布，允许按用户比例逐步开放新特性。</td></tr><tr><td><strong>Statsig</strong></td><td>分析与实验平台，用于数据采集、指标计算和实验分析。Claude Code 通过 Statsig 上报使用数据和性能指标，支撑产品决策。详见第 22 章。</td></tr></tbody></table><hr><h2 id="三、安全与权限" tabindex="-1">三、安全与权限 <a class="header-anchor" href="#三、安全与权限" aria-label="Permalink to &quot;三、安全与权限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>释义</th></tr></thead><tbody><tr><td><strong>Sandbox</strong></td><td>安全隔离环境，限制被执行代码的系统访问权限。Claude Code 的 Shell 工具在沙箱中运行用户命令，防止 LLM 生成的指令对系统造成破坏。具体实现因操作系统而异，macOS 使用 <code>sandbox-exec</code>，Linux 使用容器化方案。详见第 10 章。</td></tr><tr><td><strong>MDM</strong></td><td>Mobile Device Management 的缩写，企业级设备管理系统。在 Claude Code 的上下文中，MDM 配置作为最高优先级的配置层，允许企业 IT 管理员强制覆盖用户和项目级别的设置。详见第 4 章。</td></tr><tr><td><strong>XAA</strong></td><td>Cross-App Access 的缩写，跨应用访问认证机制。用于 MCP 服务器之间的身份验证，确保一个应用中的 MCP 客户端可以安全地访问另一个应用提供的 MCP 服务。</td></tr><tr><td><strong>PermissionMode</strong></td><td>Claude Code 的三级权限模式：<code>plan</code> 模式要求每次工具调用都经过用户确认；<code>acl</code> 模式基于预定义的允许/拒绝列表自动决策；<code>bypass</code> 模式跳过所有检查，仅限完全受信环境。详见第 17 章。</td></tr></tbody></table><hr><h2 id="四、架构与模式" tabindex="-1">四、架构与模式 <a class="header-anchor" href="#四、架构与模式" aria-label="Permalink to &quot;四、架构与模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>释义</th></tr></thead><tbody><tr><td><strong>Bridge</strong></td><td>Claude Code 中连接本地 CLI 客户端与远程执行环境（CCR）的通信系统。Bridge 负责会话建立、消息转发、断线重连和心跳维持，使远程环境对用户透明。详见第 14 章。</td></tr><tr><td><strong>CCR</strong></td><td>Claude Code Remote 的缩写，Claude Code 的远程执行环境。用户可以在本地运行 CLI 界面，而实际的代码操作在远程服务器上执行，通过 Bridge 连接。</td></tr><tr><td><strong>DCE</strong></td><td>Dead Code Elimination 的缩写，构建时的死代码消除优化。Claude Code 通过 <code>feature()</code> 函数标记条件代码路径，打包工具在构建时移除未启用的代码分支，减小最终产物体积。详见第 21 章。</td></tr><tr><td><strong>DeepImmutable</strong></td><td>TypeScript 工具类型，递归地将对象及其所有嵌套属性标记为只读。Claude Code 用它包装 <code>AppState</code>，在类型层面防止状态被意外修改。与 <code>Object.freeze</code> 的运行时冻结不同，<code>DeepImmutable</code> 是纯编译时约束，零运行时开销。</td></tr><tr><td><strong>lazySchema</strong></td><td>Claude Code 中延迟构造 Zod Schema 的设计模式。由于系统定义了大量工具，每个工具的输入 Schema 都需要 Zod 对象，如果在模块加载时就构造所有 Schema，会显著拖慢启动速度。<code>lazySchema</code> 模式将构造推迟到首次使用时，是经典的惰性初始化优化。</td></tr><tr><td><strong>profileCheckpoint</strong></td><td>启动性能分析中的埋点标记。在启动流程的关键节点调用 <code>profileCheckpoint(&quot;name&quot;)</code>，记录时间戳，用于后续分析各阶段耗时。详见第 3 章和第 21 章。</td></tr><tr><td><strong>Feature Gate</strong></td><td>功能开关机制，在运行时或构建时控制某项功能是否可用。运行时 Feature Gate 通过 GrowthBook 动态控制，构建时 Feature Gate 通过 DCE 静态消除。两种机制配合使用，兼顾灵活性和产物体积。</td></tr></tbody></table><hr><h2 id="五、git-与开发流程" tabindex="-1">五、Git 与开发流程 <a class="header-anchor" href="#五、git-与开发流程" aria-label="Permalink to &quot;五、Git 与开发流程&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>释义</th></tr></thead><tbody><tr><td><strong>Worktree</strong></td><td>Git 的工作树功能，允许在同一仓库中同时检出多个分支到不同目录。Claude Code 的 Coordinator Mode 利用 Worktree 让多个 Worker Agent 在各自独立的工作目录中并行操作，避免分支切换导致的冲突。详见第 13 章。</td></tr><tr><td><strong>REPL</strong></td><td>Read-Eval-Print Loop 的缩写，交互式命令循环。Claude Code 本身就是一个 REPL——读取用户输入、交给 LLM 评估、将结果打印到终端、循环往复。这种交互模式贯穿整个产品体验。</td></tr></tbody></table><hr><h2 id="六、术语对照速查" tabindex="-1">六、术语对照速查 <a class="header-anchor" href="#六、术语对照速查" aria-label="Permalink to &quot;六、术语对照速查&quot;">​</a></h2><p>为方便快速查找，下表按字母顺序排列所有术语及其首次出现的章节。</p><table tabindex="0"><thead><tr><th>术语</th><th>首次出现</th><th>分类</th></tr></thead><tbody><tr><td>Bridge</td><td>第 14 章</td><td>架构</td></tr><tr><td>Bun</td><td>第 21 章</td><td>工具链</td></tr><tr><td>CCR</td><td>第 14 章</td><td>架构</td></tr><tr><td>Coordinator Mode</td><td>第 13 章</td><td>AI</td></tr><tr><td>DCE</td><td>第 21 章</td><td>架构</td></tr><tr><td>DeepImmutable</td><td>第 16 章</td><td>架构</td></tr><tr><td>Elicitation</td><td>第 18 章</td><td>AI</td></tr><tr><td>Feature Gate</td><td>第 4 章</td><td>架构</td></tr><tr><td>GrowthBook</td><td>第 4 章</td><td>工具链</td></tr><tr><td>Ink</td><td>第 15 章</td><td>工具链</td></tr><tr><td>KAIROS</td><td>第 4 章</td><td>AI</td></tr><tr><td>lazySchema</td><td>第 7 章</td><td>架构</td></tr><tr><td>MCP</td><td>第 18 章</td><td>AI</td></tr><tr><td>MDM</td><td>第 4 章</td><td>安全</td></tr><tr><td>PermissionMode</td><td>第 17 章</td><td>安全</td></tr><tr><td>profileCheckpoint</td><td>第 3 章</td><td>架构</td></tr><tr><td>Prompt Cache</td><td>第 6 章</td><td>AI</td></tr><tr><td>React Reconciler</td><td>第 15 章</td><td>工具链</td></tr><tr><td>REPL</td><td>第 1 章</td><td>开发</td></tr><tr><td>Sandbox</td><td>第 10 章</td><td>安全</td></tr><tr><td>SSE</td><td>第 18 章</td><td>AI</td></tr><tr><td>Statsig</td><td>第 22 章</td><td>工具链</td></tr><tr><td>ToolSearch</td><td>第 7 章</td><td>AI</td></tr><tr><td>Worktree</td><td>第 13 章</td><td>Git</td></tr><tr><td>XAA</td><td>第 5 章</td><td>安全</td></tr><tr><td>Zod</td><td>第 4 章</td><td>工具链</td></tr></tbody></table><p>本附录收录了全书 26 个核心术语。技术领域的术语更新速度很快，部分 Claude Code 特有的概念（如 KAIROS、CCR）可能随版本迭代而演变，建议读者结合官方文档获取最新定义。</p>',22)])])}const p=d(a,[["render",n]]);export{g as __pageData,p as default};
